item.description:
//<br />这是一个 Illustrator 的脚本，此脚本将实际日期或实际时间或文件名等插入到文档中的预定义位置。<br /><br />我现在想输出的文件名可以选择性输出内容。<br /><br />例如我的文件名：1.05.07.1908 能源参数页-V1(GLEM)GGI-UT0260E-0106 SS<br /><br />在 AI 文件里一个地方放：1.05.07.1908 ，一个地方放：能源参数页-V1(GLEM)GGI-UT0260E-0106 SS<br /><br />所以我想增加 2 个功能，<br />只输出文件名前面数字部分：1.05.07.1908 （这串数字和.是固定这么长的，12 个字符？不是程序员不太懂）<br />只输出文件名数字后面部分：能源参数页-V1(GLEM)GGI-UT0260E-0106 SS<br /><br />我在 var content = content.replace(/\{FILENAME\}/,docname)后增加.slice(0,12)<br />可以单一的实现运行{FILENAME}得到：1.05.07.1908<br />或者 var content = content.replace(/\{FILENAME\}/,docname)后增加.slice(12)<br />运行{FILENAME}得到：能源参数页-V1(GLEM)GGI-UT0260E-0106 SS ，<br />但这不是我想要的结果。<br /><br />我想能否定义一个{FILENAME2}得到:1.05.07.1908 ，<br />定义一个{FILENAME3}得到:能源参数页-V1 (GLEM)GGI-UT0260E-0106 SS ，<br />是不是缺少判断语句？<br /><br />因为我不是程序员，所以我也只会简单的改下一点参数之类的东西，所以想问下有人会修改吗？或者其他方法也行不一定跟着我思路走，可能我想法和你们不一样。下面是用到的脚本代码，可能运行在 Illustrator 上的不怎么规范，有人有空能否帮忙看下怎么改，先谢谢了。<br /><br />//<br /><br />// -------------------------------------------------------------------<br /><br />var language="en";   // "de" fuer Deutsch<br /><br />// -------------------------------------------------------------------<br /><br />var WR="WR-DateAndTime v0.9

";<br /><br />var AIversion=version.slice(0,2);<br /><br />if (language == "de") {<br /><br />  var format_preset = "{FILENAME}{FILEEXT} ({DATE} - {TIME})";<br /><br />  var MSG_unsetmark = WR+"Dieses Objekt ist als aktuelles Datum/Uhrzeit markiert, soll die Markierung aufgehoben werden?";<br />  var MSG_setmark = WR+"Soll dieses Textobjekt als aktuelles Datum/Uhrzeit markiert werden?";<br />  var MSG_askformat = WR+"Soll das Textobjekt als Datum/Uhrzeit formatiert werden? Formate:
{DATE}, {TIME}, {FILE}, {FILEPATH}, {FILENAME} und {FILEEXT}:"<br />  var MSG_editformat = WR+"Datums-/Uhrzeitformat bearbeiten (Leer = entfernen). Formate:
{DATE}, {TIME}, {FILE}, {FILEPATH}, {FILENAME} und {FILEEXT}:"<br />  var MSG_notexto = WR+"Kein Textobjekt!";<br />  var MSG_selectedmany = "Zum Markieren als aktuelles Datum/Uhrzeit darf nur ein Textobjekt ausgew\xE4hlt sein und falls Sie die Daten aktualisieren wollen, darf kein Objekt ausgew\xE4hlt sein.";<br />  var MSG_nodocs = WR+"Kein Dokument ge\xF6ffnet."<br />  var Timeformat = 24;<br />  var TimeSep = ":";<br />  var AM = " am";<br />  var PM = " pm";<br />  var Dateformat = "dd.mm.yyyy";<br /><br />} else {<br /><br />  var format_preset = "{FILENAME} ({DATE}, {TIME})";<br /><br />  var MSG_unsetmark = WR+"This object is marked as actual date'n'time, do you want to remove the mark?";<br />  var MSG_setmark = WR+"Do you want to mark the selected textobject as actual date'n'time?";<br />  var MSG_askformat = WR+"Do you want to mark the textobject as actual date'n'time? Formats:
{DATE}, {TIME}, {FILE}, {FILEPATH}, {FILENAME} and {FILEEXT}:"<br />  var MSG_editformat = WR+"Edit date'n'time (empty = remove). Formats:
{DATE}, {TIME}, {FILE}, {FILEPATH}, {FILENAME} and {FILEEXT}:"<br />  var MSG_notexto = WR+"No textobject!";<br />  var MSG_selectedmany = "To mark as actual date'n'time, you have to select only one textobject. If you want to update the date'n'time-objects, there must be no object selected.";<br />  var MSG_nodocs = WR+"You have no open document."<br />  var Timeformat = 12;<br />  var TimeSep = ":";<br />  var AM = " am";<br />  var PM = " pm";<br />  var Dateformat = "mm/dd/yyyy";<br /><br />}<br /><br />var error=0;<br /><br />if (documents.length&lt;1) {<br />  error++;<br />  alert(MSG_nodocs)<br />}<br /><br />if (error &lt; 1) {<br />  date_n_time();<br />}<br /><br />function TodayDate()<br />{<br />  var Today = new Date();<br />  var Day = Today.getDate();<br />  var Month = Today.getMonth() + 1;<br />  var Year = Today.getYear();<br />  var PreMon = ((Month &lt; 10) ? "0" : "");<br />  var PreDay = ((Day &lt; 10) ? "0" : "");<br />  if(Year &lt; 999) Year += 1900;<br /><br />	var theDate = Dateformat.replace(/dd/,PreDay+Day);<br />	theDate = theDate.replace(/mm/,PreMon+Month);<br />	theDate = theDate.replace(/d/,Day);<br />	theDate = theDate.replace(/m/,Month);<br />	theDate = theDate.replace(/yyyy/,Year);<br />	theDate = theDate.replace(/yy/,Year.toString().substr(2,2));<br /><br />	return theDate;<br />}<br /><br />function TodayTime()<br />{<br />  var Today = new Date();<br />  var Hours = Today.getHours();<br />  var Minutes = Today.getMinutes();<br />  var Suffix = "";<br />  if (Timeformat == 12) {<br />    if (Hours &gt;= 12 ) {<br />			Suffix = PM;<br />		} else {<br />		  Suffix = AM;<br />		}<br />		if (Hours &gt;= 13) {<br />			Hours = Hours - 12;<br />		}<br />		if (Hours &lt; 1) {<br />			Hours = Hours + 12;<br />		}<br />	}<br />  var PreHour = ((Hours &lt; 10) ? "0" : "");<br />  var PreMin = ((Minutes &lt; 10) ? "0" : "");<br />  return PreHour+Hours+TimeSep+PreMin+Minutes+Suffix;<br />}<br /><br />function DateUpdate(Name) {<br />  var docpath = activeDocument.path.fsName;<br />  var docname = activeDocument.name.replace(/(.*?)(?:\.([^.]+))?$/,'$1');<br />  var extension = activeDocument.name.replace(/(.*?)(?:(\.[^.]+))?$/,'$2');<br />  if (docpath.slice(2,3) == "\") {<br />    docsep = "\";<br />  } else {<br />    docsep = ":";<br />  }<br />  var content = Name.slice(11);<br />  var content = content.replace(/\{FILE\}/,docpath+docsep+docname);<br />  var content = content.replace(/\{FILEPATH\}/,docpath);<br />  var content = content.replace(/\{FILENAME\}/,docname);<br />  var content = content.replace(/\{FILEEXT\}/,extension);<br />  var content = content.replace(/\{DATE\}/,TodayDate());<br />  var content = content.replace(/\{TIME\}/,TodayTime());<br />  return content;<br />}<br /><br />function date_n_time()<br />{<br />  if (selection.length == 1) {<br />    if (selection[0].typename == "TextArtItem" || selection[0].typename == "TextFrame") {<br />      if (selection[0].name.slice(0,11) == "actualDate:") {<br />        dateformat = selection[0].name.slice(11);<br />        Check = false;<br />        if (AIversion == "10") {<br />          Check = confirm( MSG_unsetmark );<br />        } else {<br />          dateformat = prompt(MSG_editformat, dateformat);<br />        }<br />        if(dateformat != "" &amp;&amp; Check) {<br />          selection[0].contents = selection[0].name.slice(11);<br />          selection[0].name="";<br />          selection[0].selected = false;<br />        }<br />        if(dateformat == "" &amp;&amp; !Check) {<br />          selection[0].name="";<br />          selection[0].selected = false;<br />        }<br />        if(dateformat &amp;&amp; dateformat !="" &amp;&amp; !Check) {<br />          selection[0].name="actualDate:"+dateformat;<br />          selection[0].contents = DateUpdate(selection[0].name);<br />        }<br />      } else {<br />        dateformat = selection[0].contents;<br />        if(dateformat.search(/\{DATE\}/) == -1 &amp;&amp; dateformat.search(/\{TIME\}/) == -1 &amp;&amp; dateformat.search(/\{FILE[A-Z]*\}/) == -1) dateformat = format_preset;<br />        Check = false;<br />        if (AIversion == "10") {<br />          Check = confirm( MSG_setmark );<br />        } else {<br />          dateformat = prompt(MSG_askformat, dateformat);<br />        }<br />        if (dateformat || Check) {<br />          selection[0].name="actualDate:"+dateformat;<br />          selection[0].contents = DateUpdate(selection[0].name);<br />          selection[0].selected = false;<br />        }<br />      }<br />    } else {<br />      alert ( MSG_notexto );<br />    }<br />  } else if (selection.length &gt; 1) {<br />    alert ( MSG_selectedmany );<br />  } else {<br />    if (AIversion == "10") {<br />      var textArtItems = activeDocument.textArtItems;<br />      for (var i = 0 ; i &lt; textArtItems.length; i++)<br />      {<br />        if (textArtItems[i].name.slice(0,11) == "actualDate:") {<br />          textArtItems[i].selected = true;<br />          textArtItems[i].contents = DateUpdate(textArtItems[i].name);<br />        }<br />      }<br />    } else {<br />      var textFrames = activeDocument.textFrames;<br />      for (var i = 0 ; i &lt; textFrames.length; i++)<br />      {<br />        if (textFrames[i].name.slice(0,11) == "actualDate:") {<br />          textFrames[i].selected = true;<br />          textFrames[i].contents = DateUpdate(textFrames[i].name);<br />        }<br />      }<br />    }<br />  }<br />}
